                local Keybind={Value=Config.Default,Toggled=false,Mode=Config.Mode or "Toggle",Type="Keybind",Callback=Config.Callback or function(Value)end,ChangedCallback=Config.ChangedCallback or function(New)end}
                local Picking=false
